import React from 'react';
import styles from './VoucherStatusBadge.module.css';

const STATUS_CLASS: Record<string, string> = {
  Draft: 'draft',
  Confirmed: 'confirmed',
  Posted: 'posted',
  Cancelled: 'cancelled',
};

const STATUS_LABEL: Record<string, string> = {
  Draft: 'Nháp',
  Confirmed: 'Đã xác nhận',
  Posted: 'Đã ghi sổ',
  Cancelled: 'Đã hủy',
};

export interface VoucherStatusBadgeProps {
  status: string;
  compact?: boolean;
  labelOverride?: string;
}

export const VoucherStatusBadge: React.FC<VoucherStatusBadgeProps> = ({
  status,
  compact = false,
  labelOverride,
}) => {
  const styleKey = STATUS_CLASS[status] ?? 'default';
  const label = labelOverride ?? STATUS_LABEL[status] ?? status;

  return (
    <span
      className={`${styles.badge} ${styles[styleKey]} ${compact ? styles.compact : ''}`}
      data-testid={`voucher-status-badge-${status.toLowerCase()}`}
    >
      <span className={styles.dot} aria-hidden />
      <span className={styles.label}>{label}</span>
    </span>
  );
};
